import { useState } from 'react'
import type { ShellMobileDestination } from '@ds-mo/ui/shell'
import { DsBarNav, DsPanelNav, DsShellApp, DsShellMobileBar, DsShellMobileNav, DsShellMobileSectionNav, DsShellTools } from '@ds-mo/ui/react'

export function AppShell() {
  const [destination, setDestination] = useState<ShellMobileDestination>('area')
  const [navigationOpen, setNavigationOpen] = useState(false)
  return (
    <DsShellApp mobileDestination={destination} mobileNavigationOpen={navigationOpen}>
      <DsPanelNav slot="panel" />
      <DsShellMobileNav slot="mobile-navigation" open={navigationOpen} />
      <DsBarNav slot="bar" />
      <DsShellMobileSectionNav slot="mobile-section-nav" />
      <DsShellTools slot="tools"><div slot="search-view">Search</div></DsShellTools>
      <main>{/* routed workspace */}</main>
      <DsShellMobileBar slot="mobile-bar" activeDestination={destination} navigationExpanded={navigationOpen} onDsNavigationToggle={event => setNavigationOpen(event.detail)} onDsDestinationChange={event => { setNavigationOpen(false); setDestination(event.detail.destination) }} />
    </DsShellApp>
  )
}
